import { join } from 'node:path';
import type { KnowledgeScope } from './scopes.js';
import { humanizeKebab } from '../utils/strings.js';

/**
 * Standard area → directory name mapping.
 * Used to resolve Knowledge paths from area keys.
 */
export const AREA_DIR_MAP: Record<string, string> = {
  'adr': 'ADR',
  'tldr': 'TLDR',
  'roadmap': 'Roadmap',
  'design': 'Design',
  'guides': 'Guides',
  'agent-memory': 'AgentMemory',
  'runbooks': 'runbooks',
  'threat-models': 'ThreatModels',
  'templates': 'Templates',
  'governance': 'governance',
  'context-pack': '',   // ContextPack.md lives at Knowledge root
  'index': '',          // INDEX.md lives at Knowledge root
};

/**
 * Resolve the absolute path for an area within a Knowledge scope.
 *
 * Per R1: package docs live at Knowledge/packages/<name>/<area>/
 * Root docs live at Knowledge/<area>/
 * Category docs live at Knowledge/<category-name>/
 */
export function knowledgePath(scope: KnowledgeScope, area: string, filename?: string): string {
  if (scope.type === 'category') {
    // Categories are direct subdirectories of Knowledge root
    return filename ? join(scope.knowledgeRoot, filename) : scope.knowledgeRoot;
  }

  const dirName = AREA_DIR_MAP[area] ?? area;
  const areaPath = dirName ? join(scope.knowledgeRoot, dirName) : scope.knowledgeRoot;
  return filename ? join(areaPath, filename) : areaPath;
}

/**
 * Get the wikilink path for a document in a scope, relative to Knowledge root.
 * Used to generate cross-references.
 *
 * Per R1: [[ADR/ADR-0001]] for root, [[packages/codegraph/ADR/ADR-0001]] for packages
 */
export function wikilinkPath(scope: KnowledgeScope, area: string, docName: string): string {
  const dirName = AREA_DIR_MAP[area] ?? area;

  if (scope.type === 'root') {
    return dirName ? `${dirName}/${docName}` : docName;
  }

  if (scope.type === 'package') {
    return dirName ? `packages/${scope.name}/${dirName}/${docName}` : `packages/${scope.name}/${docName}`;
  }

  // category
  return `${scope.name}/${docName}`;
}

export { humanizeKebab };
