// cli/src/commands/mcp.ts
import { Command } from 'commander';

export function registerMcpCommand(program: Command): void {
  const cmd = new Command('mcp');

  cmd
    .description('Start the kdoc MCP server (stdio transport)')
    .option('--project <dir>', 'Project directory (defaults to cwd)')
    .action(async () => {
      const { startServer, parseProjectDir } = await import('../mcp/server.js');
      const projectDir = parseProjectDir(process.argv, process.cwd());
      await startServer(projectDir);
    });

  program.addCommand(cmd);
}
