import { readFileSync, existsSync } from 'node:fs';
import { join } from 'node:path';
import type { Phase, DependencyGraph, Wave } from './index.js';
import { getExecutionWaves, getCriticalPath } from './graph.js';
import { safeWriteFile } from '../utils/fs.js';

const AUTOGEN_START = '<!-- ROADMAP_AUTOGEN:START -->';
const AUTOGEN_END = '<!-- ROADMAP_AUTOGEN:END -->';

function statusIcon(status: string): string {
  switch (status) {
    case 'completed':
    case 'completed_with_notes':
      return '✅';
    case 'in_progress':
      return '🔄';
    case 'blocked':
      return '🚫';
    default:
      return '⏳';
  }
}

function formatProgress(phase: Phase): string {
  const total = phase.subPhases.length || phase.workUnitsTotal;
  if (total === 0) return '—';
  const done = phase.subPhases.filter(s => s.status === 'completed').length;
  const pct = total > 0 ? Math.round((done / total) * 100) : 0;
  return `${done}/${total} (${pct}%)`;
}

function findNextUp(phase: Phase, graph: DependencyGraph): string[] {
  return phase.subPhases
    .filter(s => s.status === 'pending' || s.status === 'in_progress')
    .filter(s => {
      const deps = graph.edges.get(s.id) ?? [];
      return deps.every(d => {
        const node = graph.nodes.get(d);
        if (!node) return true;
        return 'status' in node && (node.status === 'completed' || node.status === 'completed_with_notes');
      });
    })
    .map(s => `[[${s.id}]]`)
    .slice(0, 3);
}

/**
 * Generate dashboard markdown content for a set of phases.
 */
export function generateDashboardContent(phases: Phase[], graph: DependencyGraph): string {
  const lines: string[] = [];

  lines.push('## Progress Dashboard');
  lines.push('');
  lines.push(`**Last generated**: ${new Date().toISOString().slice(0, 10)}`);
  lines.push('');

  // Phase table
  lines.push('| Phase | Name | Status | Progress | Blocked By | Next Up |');
  lines.push('|-------|------|--------|----------|-----------|---------|');

  for (const phase of phases) {
    const num = phase.id.replace('phase-', '');
    const status = `${statusIcon(phase.status)} ${phase.status}`;
    const progress = formatProgress(phase);
    const blockedBy = phase.dependsOn.length > 0 ? phase.dependsOn.join(', ') : '—';
    const nextUp = findNextUp(phase, graph);
    const nextStr = nextUp.length > 0 ? nextUp.join(', ') : '—';
    lines.push(`| ${num} | ${phase.name} | ${status} | ${progress} | ${blockedBy} | ${nextStr} |`);
  }

  // Execution waves for current active phase
  const activePhase = phases.find(p => p.status === 'in_progress');
  if (activePhase && activePhase.subPhases.length > 0) {
    const waves = getExecutionWaves(graph);
    const phaseSubIds = new Set(activePhase.subPhases.map(s => s.id));

    lines.push('');
    lines.push(`### Execution Waves (${activePhase.name})`);

    for (const wave of waves) {
      const phaseWaveItems = wave.items.filter(id => phaseSubIds.has(id));
      if (phaseWaveItems.length === 0) continue;

      const itemNames = phaseWaveItems.map(id => {
        const sub = activePhase.subPhases.find(s => s.id === id);
        return sub ? `[[${sub.id}]]` : id;
      });
      lines.push(`- **Wave ${wave.number}**: ${itemNames.join(', ')}`);
    }
  }

  // Critical path
  const criticalPath = getCriticalPath(graph);
  if (criticalPath.length > 1) {
    lines.push('');
    lines.push('### Critical Path');
    lines.push(criticalPath.join(' → '));
  }

  lines.push('');
  return lines.join('\n');
}

/**
 * Write dashboard to README.md between autogen markers.
 * If markers don't exist, appends them.
 */
export function writeDashboard(readmePath: string, dashboardContent: string): void {
  let existing = '';
  if (existsSync(readmePath)) {
    existing = readFileSync(readmePath, 'utf8');
  }

  const startIdx = existing.indexOf(AUTOGEN_START);
  const endIdx = existing.indexOf(AUTOGEN_END);

  let updated: string;
  if (startIdx !== -1 && endIdx !== -1) {
    // Replace content between markers
    updated =
      existing.slice(0, startIdx) +
      AUTOGEN_START + '\n' +
      dashboardContent +
      AUTOGEN_END +
      existing.slice(endIdx + AUTOGEN_END.length);
  } else {
    // Append markers
    updated = existing.trimEnd() + '\n\n' + AUTOGEN_START + '\n' + dashboardContent + AUTOGEN_END + '\n';
  }

  safeWriteFile(readmePath, updated);
}
