import type { RepairResult, RepairTier, RepairableFinding } from './types.js';

const TIER_ORDER: RepairTier[] = ['auto-fix', 'needs-approval', 'report-only'];
const STATUS_ORDER: RepairResult['status'][] = ['applied', 'skipped', 'failed'];

function groupByTier(findings: RepairableFinding[]): Map<RepairTier, RepairableFinding[]> {
  const grouped = new Map<RepairTier, RepairableFinding[]>();
  for (const tier of TIER_ORDER) {
    grouped.set(tier, findings.filter((finding) => finding.tier === tier));
  }
  return grouped;
}

function groupByFile<T extends { filePath: string }>(items: T[]): Map<string, T[]> {
  const grouped = new Map<string, T[]>();
  for (const item of items) {
    const current = grouped.get(item.filePath) ?? [];
    current.push(item);
    grouped.set(item.filePath, current);
  }
  return new Map([...grouped.entries()].sort(([a], [b]) => a.localeCompare(b)));
}

function renderFindingLine(finding: RepairableFinding): string {
  let reason = '';
  if (finding.context.code === 'BROKEN_WIKILINK' && finding.context.candidates.length !== 1) {
    reason = ` reason: ${
      finding.context.candidates.length === 0
        ? 'no deterministic target found'
        : `ambiguous candidates (${finding.context.candidates.join(', ')})`
    }`;
  }
  return `  - [${finding.code}] ${finding.message}${reason}`;
}

export function formatFindingReport(findings: RepairableFinding[]): string {
  if (findings.length === 0) {
    return 'No pending repairs.';
  }

  const lines = [`Pending repairs: ${findings.length}`];
  const byTier = groupByTier(findings);

  for (const tier of TIER_ORDER) {
    const tierFindings = byTier.get(tier) ?? [];
    if (tierFindings.length === 0) continue;

    lines.push('', `${tier} (${tierFindings.length})`);

    for (const [filePath, fileFindings] of groupByFile(tierFindings)) {
      lines.push(`- ${filePath}`);
      for (const finding of fileFindings) {
        lines.push(renderFindingLine(finding));
      }
    }
  }

  return lines.join('\n');
}

function renderResultLine(result: RepairResult): string {
  const status = result.status.toUpperCase();
  const reason = result.reason ? ` reason: ${result.reason}` : '';
  return `  - ${status} [${result.finding.code}] ${result.finding.message}${reason}`;
}

export function formatRepairResults(results: RepairResult[]): string {
  if (results.length === 0) {
    return 'No repairs executed.';
  }

  const lines = ['Repair results'];

  for (const status of STATUS_ORDER) {
    const statusResults = results.filter((result) => result.status === status);
    if (statusResults.length === 0) continue;

    lines.push('', `${status} (${statusResults.length})`);

    for (const [filePath, fileResults] of groupByFile(
      statusResults.map((result) => ({ ...result, filePath: result.finding.filePath })),
    )) {
      lines.push(`- ${filePath}`);
      for (const result of fileResults) {
        lines.push(renderResultLine(result));
      }
    }
  }

  return lines.join('\n');
}
