import { Command } from 'commander';
import { readFileSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { createInitCommand } from './commands/init.js';
import { createAddCommand, createAddPackCommand, createAddToolCommand } from './commands/add.js';
import { registerUpdateCommand } from './commands/update.js';
import { registerDoctorCommand } from './commands/doctor.js';
import { registerCreateCommand } from './commands/create.js';
import { registerUndoCommand } from './commands/undo.js';
import { registerSelftestCommand } from './commands/selftest.js';
import { registerBriefCommand } from './commands/brief.js';
import { registerGenerateCommand } from './commands/generate.js';
import { registerRoadmapCommand } from './commands/roadmap.js';
import { registerMcpCommand } from './commands/mcp.js';
import { registerReconcileCommand } from './commands/reconcile.js';

const __dirname = dirname(fileURLToPath(import.meta.url));

// Read version from package.json at runtime (survives build and version bumps)
function getVersion(): string {
  try {
    const pkgPath = join(__dirname, '..', 'package.json');
    const pkg = JSON.parse(readFileSync(pkgPath, 'utf8')) as { version: string };
    return pkg.version;
  } catch {
    return '0.0.0';
  }
}

export function buildProgram(): Command {
  const program = new Command();

  program
    .name('kdoc')
    .description('Knowledge documentation toolkit — scaffold, maintain, and govern project docs')
    .version(getVersion(), '-v, --version', 'Print the current version')
    .enablePositionalOptions()
    // Global flags available to all subcommands
    .option('--yes', 'Non-interactive: skip all prompts and use detected defaults')
    .option('--force', 'Overwrite user-modified content without asking (implies --yes)')
    .option('--dry-run', 'Show what would be done without making changes')
    .option('--verbose', 'Log each file operation as it runs');

  // Register commands — Plan 2A
  program.addCommand(createInitCommand());
  program.addCommand(createAddCommand());
  program.addCommand(createAddPackCommand());
  program.addCommand(createAddToolCommand());

  // Register commands — Plan 2B
  registerUpdateCommand(program);
  registerDoctorCommand(program);
  registerCreateCommand(program);
  registerUndoCommand(program);
  registerSelftestCommand(program);
  registerBriefCommand(program);
  registerGenerateCommand(program);
  registerReconcileCommand(program);
  registerRoadmapCommand(program);
  registerMcpCommand(program);

  return program;
}

// Only parse when running as the direct entry point
const isMainModule = process.argv[1] && fileURLToPath(import.meta.url) === process.argv[1];
if (isMainModule) {
  buildProgram().parse();
}
