// cli/src/commands/selftest.ts
import { Command } from 'commander';
import { spawnSync } from 'node:child_process';
import { mkdtempSync, readdirSync, readFileSync, writeFileSync, rmSync } from 'node:fs';
import { join, relative, dirname } from 'node:path';
import { tmpdir } from 'node:os';
import { createHash } from 'node:crypto';
import { fileURLToPath } from 'node:url';

// ---- Snapshot engine (self-contained, no test deps) ----

interface FileEntry {
  hash: string;
  size: number;
  isDirectory: boolean;
}

type Snapshot = Record<string, FileEntry>;

function hashBuffer(buf: Buffer): string {
  return 'sha256:' + createHash('sha256').update(buf).digest('hex');
}

function captureSnapshot(rootDir: string): Snapshot {
  const snapshot: Snapshot = {};
  function walk(dir: string): void {
    for (const entry of readdirSync(dir, { withFileTypes: true })) {
      const fullPath = join(dir, entry.name);
      const relPath = relative(rootDir, fullPath);
      if (entry.isDirectory()) {
        snapshot[relPath] = { hash: '', size: 0, isDirectory: true };
        walk(fullPath);
      } else {
        const buf = readFileSync(fullPath);
        snapshot[relPath] = {
          hash: hashBuffer(buf),
          size: buf.length,
          isDirectory: false,
        };
      }
    }
  }
  walk(rootDir);
  return snapshot;
}

function diffSnapshots(a: Snapshot, b: Snapshot): { added: string[]; removed: string[]; changed: string[] } {
  const added = Object.keys(b).filter(k => !(k in a));
  const removed = Object.keys(a).filter(k => !(k in b));
  const changed = Object.keys(a).filter(k => k in b && a[k].hash !== b[k].hash);
  return { added, removed, changed };
}

// ---- CLI runner ----

interface KdocRunResult {
  ok: boolean;
  stdout: string;
  stderr: string;
  status: number;
  error: string | null;
  signal: NodeJS.Signals | null;
}

// Resolve CLI entry point via import.meta.url (works with npx, pnpm, direct node)
// tsup bundles everything into dist/index.js, so this file IS dist/index.js at runtime.
const __selftest_filename = fileURLToPath(import.meta.url);

function runKdoc(args: string[], cwd: string): KdocRunResult {
  const cliPath = __selftest_filename;
  const childEnv: Record<string, string | undefined> = { ...process.env };
  delete childEnv.VITEST;
  delete childEnv.KDOC_PROJECT_DIR;
  const result = spawnSync('node', [cliPath, ...args], {
    encoding: 'utf8',
    timeout: 30_000,
    cwd,
    env: childEnv,
  });
  return {
    ok: result.status === 0,
    stdout: result.stdout ?? '',
    stderr: result.stderr ?? '',
    status: result.status ?? 1,
    error: result.error?.message ?? null,
    signal: result.signal ?? null,
  };
}

// ---- Test steps ----

interface StepResult {
  name: string;
  passed: boolean;
  detail: string;
}

interface StepOutcome {
  passed?: boolean;
  detail: string;
}

function formatRunFailure(prefix: string, result: KdocRunResult): string {
  const parts = [`${prefix} (exit ${result.status})`];
  if (result.signal) parts.push(`signal: ${result.signal}`);
  if (result.error) parts.push(`spawn error: ${result.error}`);
  const output = result.stderr || result.stdout;
  if (output) parts.push(output.slice(0, 200));
  return parts.join(': ');
}

function step(name: string, fn: () => string | StepOutcome | null): StepResult {
  try {
    const outcome = fn();
    if (typeof outcome === 'string') {
      return { name, passed: false, detail: outcome };
    }
    if (outcome) {
      return { name, passed: outcome.passed ?? false, detail: outcome.detail };
    }
    return { name, passed: true, detail: 'ok' };
  } catch (e) {
    return { name, passed: false, detail: e instanceof Error ? e.message : String(e) };
  }
}

function runSelftest(opts: { pack?: string; tools?: string; verbose?: boolean }): StepResult[] {
  const results: StepResult[] = [];
  const tmpDir = mkdtempSync(join(tmpdir(), 'kdoc-selftest-'));

  try {
    // Step 1: Capture empty state
    const emptySnapshot = captureSnapshot(tmpDir);
    results.push({ name: 'prepare', passed: true, detail: `temp dir: ${tmpDir}` });

    // Step 2: Init
    const initArgs = ['init', '--yes'];
    if (opts.pack) initArgs.push('--pack', opts.pack);
    if (opts.tools) initArgs.push('--tools', opts.tools);

    results.push(step('init', () => {
      const r = runKdoc(initArgs, tmpDir);
      if (opts.verbose) process.stderr.write(r.stdout + r.stderr);
      if (!r.ok) return formatRunFailure('init failed', r);
      return null;
    }));
    if (!results[results.length - 1].passed) return results;

    // Step 3: Snapshot after init
    const initSnapshot = captureSnapshot(tmpDir);
    const initFileCount = Object.keys(initSnapshot).filter(k => !initSnapshot[k].isDirectory).length;
    results.push({ name: 'snapshot', passed: true, detail: `${initFileCount} files created` });

    // Step 4: Doctor — verify init didn't produce a broken state
    // Note: bare init without a pack may report structure warnings (missing ADR/TLDR dirs).
    // We don't fail selftest for check failures, but we do report them visibly.
    results.push(step('doctor', () => {
      const r = runKdoc(['doctor', '--json'], tmpDir);
      if (opts.verbose) process.stderr.write(r.stdout + r.stderr);
      try {
        const report = JSON.parse(r.stdout);
        const fails = report.checks?.filter((c: { status: string }) => c.status === 'fail') ?? [];
        if (fails.length > 0) {
          return { passed: true, detail: `${fails.length} check failures (non-blocking)` };
        }
        return null;
      } catch {
        return formatRunFailure('doctor produced invalid JSON', r);
      }
    }));

    // Step 5: Mutate 3 files
    results.push(step('mutate', () => {
      // Find files to mutate from the snapshot
      const files = Object.keys(initSnapshot).filter(k => !initSnapshot[k].isDirectory);
      const mutations: string[] = [];

      // Mutation 1: Append to a created file
      const readmeFile = files.find(f => f.includes('README.md')) ?? files[0];
      if (readmeFile) {
        const fullPath = join(tmpDir, readmeFile);
        const content = readFileSync(fullPath, 'utf8');
        writeFileSync(fullPath, content + '\n\n## User addition\nThis was added by the user.\n');
        mutations.push(`appended: ${readmeFile}`);
      }

      // Mutation 2: Modify a different file
      const otherFile = files.find(f => f !== readmeFile && f.endsWith('.md'));
      if (otherFile) {
        const fullPath = join(tmpDir, otherFile);
        const content = readFileSync(fullPath, 'utf8');
        writeFileSync(fullPath, content + '\nModified by selftest.\n');
        mutations.push(`modified: ${otherFile}`);
      }

      // Mutation 3: Modify .kdoc.yaml to simulate user edit
      const configFile = files.find(f => f === '.kdoc.yaml');
      if (configFile) {
        const fullPath = join(tmpDir, configFile);
        const content = readFileSync(fullPath, 'utf8');
        writeFileSync(fullPath, content + '\n# User comment\n');
        mutations.push(`edited: ${configFile}`);
      }

      if (mutations.length === 0) return 'no files to mutate';
      return null;
    }));

    // Step 6: Re-init with same flags (should detect conflicts/changes)
    results.push(step('re-init', () => {
      const r = runKdoc(initArgs, tmpDir);
      if (opts.verbose) process.stderr.write(r.stdout + r.stderr);
      if (r.status !== 0 && r.status !== 1) {
        return formatRunFailure('re-init failed', r);
      }
      const combinedOutput = `${r.stdout}\n${r.stderr}`.toLowerCase();
      if (!/(conflict|modified|skip)/.test(combinedOutput)) {
        return 're-init did not report a conflict signal in stdout/stderr';
      }
      return null;
    }));

    // Step 7: Undo
    results.push(step('undo', () => {
      const r = runKdoc(['undo', '--yes', '--force'], tmpDir);
      if (opts.verbose) process.stderr.write(r.stdout + r.stderr);
      if (!r.ok) return formatRunFailure('undo failed', r);
      return null;
    }));

    // Step 8: Verify identity
    // Note: undo --yes keeps .kdoc.yaml by design (safe default). We exclude it from comparison.
    results.push(step('identity', () => {
      const afterUndo = captureSnapshot(tmpDir);
      const diff = diffSnapshots(emptySnapshot, afterUndo);
      // .kdoc.yaml is intentionally kept by undo — filter it out
      const leftover = [...diff.added, ...diff.changed].filter(f => f !== '.kdoc.yaml');
      if (leftover.length > 0) {
        return `undo left ${leftover.length} file(s) behind: ${leftover.slice(0, 5).join(', ')}${leftover.length > 5 ? '...' : ''}`;
      }
      if (diff.removed.length > 0) {
        return `undo removed ${diff.removed.length} pre-existing file(s): ${diff.removed.join(', ')}`;
      }
      return null;
    }));
  } finally {
    // Cleanup temp dir
    try { rmSync(tmpDir, { recursive: true, force: true }); } catch { /* ignore */ }
  }

  return results;
}

// ---- Command registration ----

export function registerSelftestCommand(program: Command): void {
  program
    .command('selftest')
    .description('Verify kdoc works correctly: init → doctor → mutate → undo → assert clean')
    .option('--pack <pack>', 'Pack to test with (default: none)')
    .option('--tools <tools>', 'Tools to test with (default: none)')
    .option('--verbose', 'Show command output during test')
    .action((opts: { pack?: string; tools?: string; verbose?: boolean }) => {
      console.log('kdoc selftest — round-trip verification\n');

      const results = runSelftest(opts);
      const passed = results.filter(r => r.passed).length;
      const failed = results.filter(r => !r.passed).length;

      for (const r of results) {
        const icon = r.passed ? '\u2713' : '\u2717';
        const line = `  ${icon} ${r.name}: ${r.detail}`;
        console.log(line);
      }

      console.log(`\n${passed} passed, ${failed} failed`);

      if (failed > 0) {
        console.log('\nSelftest FAILED. Please report this issue.');
        process.exit(1);
      } else {
        console.log('\nSelftest PASSED. kdoc is working correctly.');
      }
    });
}
