import { existsSync, mkdirSync, readFileSync } from 'node:fs';
import { join } from 'node:path';
import { Command } from 'commander';
import type { AreaConfig } from '../config/schema.js';
import { loadConfig, writeConfig, configExists } from '../config/loader.js';
import { loadLock } from '../config/lock.js';
import { detectProject } from '../scaffold/detect.js';
import { planScaffold } from '../scaffold/plan.js';
import { executeScaffold } from '../scaffold/execute.js';
import type { KdocConfig } from '../config/schema.js';
import type { TemplateResolver } from '../scaffold/plan.js';
import { getKdocVersion } from '../utils/version.js';
import { createTemplateResolver } from '../templates/catalog.js';
import { KNOWN_AREAS, KNOWN_PACKS, KNOWN_TOOLS, SYNTHETIC_TEMPLATES, AREA_DIR_MAP } from '../constants.js';
import { installPackAssets } from '../packs/installer.js';
import { runToolInstaller } from '../integrations/runner.js';

function getProjectDir(): string {
  return process.env.KDOC_PROJECT_DIR ?? process.cwd();
}

function makeTemplateResolver(): TemplateResolver {
  return createTemplateResolver(SYNTHETIC_TEMPLATES);
}

/**
 * Execute a scoped scaffold using the provided config. Returns true on success,
 * false if any errors occurred (caller decides whether to persist config).
 *
 * Transactional guarantee: this function never writes the config file. The
 * caller writes it only after this function returns true.
 */
async function runScopedScaffold(
  projectDir: string,
  updatedConfig: KdocConfig,
  { force = false }: { force?: boolean } = {},
): Promise<boolean> {
  const detection = await detectProject(projectDir);
  const existingLock = loadLock(projectDir);
  const resolver = makeTemplateResolver();

  const operations = planScaffold({
    config: updatedConfig,
    detection,
    lock: existingLock,
    projectDir,
    templateResolver: resolver,
  });

  const templateContents = new Map<string, string>();
  for (const op of operations) {
    const resolved = resolver(op.source);
    if (resolved) {
      templateContents.set(op.source, resolved.content);
    } else if (existsSync(op.source)) {
      // op.source is an absolute path from a previous resolution — read directly
      templateContents.set(op.source, readFileSync(op.source, 'utf8'));
    }
  }

  const summary = await executeScaffold({
    operations,
    config: updatedConfig,
    projectDir,
    kdocVersion: getKdocVersion(),
    templateContents,
    force,
  });

  if (summary.errors.length > 0) {
    console.error('Scaffold errors:');
    for (const e of summary.errors) console.error(`  - ${e.path}: ${e.error}`);
    return false;
  }

  const creates = summary.created.length;
  const merges = summary.merged.length;
  const skips = summary.skipped.length;
  console.log(`Done: ${creates} created, ${merges} merged, ${skips} skipped`);
  return true;
}

export function createAddCommand(): Command {
  const cmd = new Command('add');

  cmd
    .description('Add a Knowledge area to an existing kdoc installation')
    .argument('<area>', `Area to add (${KNOWN_AREAS.join(', ')})`)
    .option('--package <name>', 'Enable the area only for a configured package scope')
    .option('--yes', 'Non-interactive mode')
    .option('--force', 'Overwrite user-modified managed files without asking')
    .option('--verbose', 'Log each file operation as it runs')
    .action(async (area: string, options: { force?: boolean; yes?: boolean; package?: string; verbose?: boolean }) => {
      const projectDir = getProjectDir();

      if (!configExists(projectDir)) {
        console.error('Error: No .kdoc.yaml found. Run `kdoc init` first.');
        process.exitCode = 1;
        return;
      }

      if (!(KNOWN_AREAS as readonly string[]).includes(area)) {
        console.error(
          `Error: Unknown area "${area}". Valid areas: ${KNOWN_AREAS.join(', ')}`,
        );
        process.exitCode = 1;
        return;
      }

      try {
        const config = loadConfig(projectDir);
        if (!config) {
          console.error('Error: Failed to load .kdoc.yaml.');
          process.exitCode = 1;
          return;
        }

        // Compute updated config in memory — do NOT write yet (transactional guarantee)
        let updatedConfig: KdocConfig;

        if (options.package) {
          if (config.topology !== 'monorepo') {
            console.error('Error: --package can only be used when topology is "monorepo".');
            process.exitCode = 1;
            return;
          }

          const packageConfig = config.packages?.[options.package];
          if (!packageConfig) {
            console.error(
              `Error: Unknown package "${options.package}". Valid packages: ${Object.keys(config.packages ?? {}).join(', ')}`,
            );
            process.exitCode = 1;
            return;
          }

          const inheritedAreas: Record<string, AreaConfig> = {
            ...config.areas,
            ...(packageConfig.areas ?? {}),
          };

          updatedConfig = {
            ...config,
            packages: {
              ...config.packages,
              [options.package]: {
                ...packageConfig,
                areas: {
                  ...inheritedAreas,
                  [area]: { enabled: true },
                },
              },
            },
          };
        } else {
          updatedConfig = {
            ...config,
            areas: {
              ...config.areas,
              [area]: { enabled: true },
            },
          };
        }

        const success = await runScopedScaffold(projectDir, updatedConfig, { force: !!options.force });
        if (success) {
          // F-008: Ensure area directories exist even if no template files are defined.
          // Some areas (design, threat-models, governance) need directories but have
          // no scaffold templates. Create the directory so doctor doesn't fail.
          const dirName = AREA_DIR_MAP[area];
          if (dirName) {
            const knowledgeRoot = updatedConfig.root ?? 'Knowledge';
            // For --package, create under package Knowledge root
            const baseDir = options.package
              ? join(projectDir, knowledgeRoot, 'packages', options.package)
              : join(projectDir, knowledgeRoot);
            mkdirSync(join(baseDir, dirName), { recursive: true });
          }

          // Only persist config after successful scaffold execution
          writeConfig(projectDir, updatedConfig);
          console.log(
            options.package
              ? `Area "${area}" added successfully for package "${options.package}".`
              : `Area "${area}" added successfully.`,
          );
        } else {
          // Config is NOT written — transaction implicitly rolled back
          process.exitCode = 1;
        }
      } catch (err) {
        console.error(`Error: ${err instanceof Error ? err.message : String(err)}`);
        process.exitCode = 1;
      }
    });

  return cmd;
}

export function createAddPackCommand(): Command {
  const cmd = new Command('add-pack');

  cmd
    .description('Add a technology pack to an existing kdoc installation')
    .argument('<pack>', `Pack to add (${KNOWN_PACKS.join(', ')})`)
    .option('--yes', 'Non-interactive mode')
    .option('--dry-run', 'Show what would be done without making changes')
    .action(async (pack: string, options: { force?: boolean; yes?: boolean; dryRun?: boolean }) => {
      const projectDir = getProjectDir();

      if (!configExists(projectDir)) {
        console.error('Error: No .kdoc.yaml found. Run `kdoc init` first.');
        process.exitCode = 1;
        return;
      }

      if (!(KNOWN_PACKS as readonly string[]).includes(pack)) {
        console.error(
          `Error: Unknown pack "${pack}". Valid packs: ${KNOWN_PACKS.join(', ')}`,
        );
        process.exitCode = 1;
        return;
      }

      try {
        const config = loadConfig(projectDir);
        if (!config) {
          console.error('Error: Failed to load .kdoc.yaml.');
          process.exitCode = 1;
          return;
        }

        // Compute updated config in memory — do NOT write yet (transactional guarantee)
        const updatedConfig: KdocConfig = {
          ...config,
          // Use Set to deduplicate — idempotent if pack already present
          packs: [...new Set([...config.packs, pack])],
        };

        if (options.dryRun) {
          console.log(`[DRY RUN] Would add pack "${pack}" to config.`);
          console.log(`[DRY RUN] Would run scaffold with updated config.`);
          const packResult = await installPackAssets(pack, projectDir, updatedConfig, { dryRun: true });
          if (packResult.installed.length > 0) {
            console.log(`[DRY RUN] Pack assets to install:`);
            for (const f of packResult.installed) console.log(`  [CREATE  ] ${f}`);
          }
          if (packResult.skipped.length > 0) {
            console.log(`[DRY RUN] Pack assets already present:`);
            for (const f of packResult.skipped) console.log(`  [SKIP    ] ${f}`);
          }
          return;
        }

        const success = await runScopedScaffold(projectDir, updatedConfig, { force: !!options.force });
        if (success) {
          // Install pack assets (templates, guides, design, scripts)
          const packResult = await installPackAssets(pack, projectDir, updatedConfig, {
            force: !!options.force,
          });
          if (packResult.errors.length > 0) {
            for (const e of packResult.errors) console.warn(`Warning: ${e}`);
          }

          writeConfig(projectDir, updatedConfig);
          const packInstalled = packResult.installed.length;
          const packSkipped = packResult.skipped.length;
          console.log(`Pack "${pack}" added successfully.${packInstalled > 0 ? ` ${packInstalled} assets installed, ${packSkipped} skipped.` : ''}`);
        } else {
          process.exitCode = 1;
        }
      } catch (err) {
        console.error(`Error: ${err instanceof Error ? err.message : String(err)}`);
        process.exitCode = 1;
      }
    });

  return cmd;
}

export function createAddToolCommand(): Command {
  const cmd = new Command('add-tool');

  cmd
    .description('Add an AI tool integration to an existing kdoc installation')
    .argument('<tool>', `Tool to add (${KNOWN_TOOLS.join(', ')})`)
    .option('--yes', 'Non-interactive mode')
    .option('--force', 'Overwrite user-modified managed files without asking')
    .option('--dry-run', 'Show what would be done without making changes')
    .action(async (tool: string, options: { force?: boolean; yes?: boolean; dryRun?: boolean }) => {
      const projectDir = getProjectDir();

      if (!configExists(projectDir)) {
        console.error('Error: No .kdoc.yaml found. Run `kdoc init` first.');
        process.exitCode = 1;
        return;
      }

      if (!(KNOWN_TOOLS as readonly string[]).includes(tool)) {
        console.error(
          `Error: Unknown tool "${tool}". Valid tools: ${KNOWN_TOOLS.join(', ')}`,
        );
        process.exitCode = 1;
        return;
      }

      try {
        const config = loadConfig(projectDir);
        if (!config) {
          console.error('Error: Failed to load .kdoc.yaml.');
          process.exitCode = 1;
          return;
        }

        // Compute updated config in memory — do NOT write yet (transactional guarantee)
        const updatedConfig: KdocConfig = {
          ...config,
          // Use Set to deduplicate — idempotent if tool already present
          tools: [...new Set([...config.tools, tool])],
        };

        if (options.dryRun) {
          console.log(`[DRY RUN] Would add tool "${tool}" to config.`);
          console.log(`[DRY RUN] Would run scaffold with updated config.`);
          const toolResult = runToolInstaller(tool, projectDir, {
            dryRun: true,
            yes: !!options.yes,
          });
          console.log(
            `[DRY RUN] Tool installer would create ${toolResult.manifest.created.length} file(s), merge ${toolResult.manifest.merged.length} file(s), and skip ${toolResult.manifest.skipped.length} file(s).`,
          );
          for (const warning of toolResult.warnings) {
            console.warn(`Warning: ${warning}`);
          }
          return;
        }

        const success = await runScopedScaffold(projectDir, updatedConfig, { force: !!options.force });
        if (success) {
          writeConfig(projectDir, updatedConfig);
          const toolResult = runToolInstaller(tool, projectDir, {
            yes: !!options.yes,
          });
          for (const warning of toolResult.warnings) {
            console.warn(`Warning: ${warning}`);
          }
          console.log(`Tool "${tool}" added successfully.`);
        } else {
          process.exitCode = 1;
        }
      } catch (err) {
        console.error(`Error: ${err instanceof Error ? err.message : String(err)}`);
        process.exitCode = 1;
      }
    });

  return cmd;
}
