import { existsSync, readFileSync } from 'node:fs';
import { join } from 'node:path';
import { Command } from 'commander';
import { checkbox, input, select } from '@inquirer/prompts';
import { detectPackages, detectProject, detectTopology } from '../scaffold/detect.js';
import { planScaffold } from '../scaffold/plan.js';
import { executeScaffold } from '../scaffold/execute.js';
import { configExists, loadConfig, writeConfig } from '../config/loader.js';
import { loadLock, hasPendingLockTmp, cleanupLockTmp } from '../config/lock.js';
import type { KdocConfig } from '../config/schema.js';
import type { TemplateResolver } from '../scaffold/plan.js';
import { getKdocVersion } from '../utils/version.js';
import { createTemplateResolver } from '../templates/catalog.js';
import { KNOWN_PACKS, KNOWN_TOOLS, KNOWN_AREAS, SYNTHETIC_TEMPLATES } from '../constants.js';
import { installPackAssets } from '../packs/installer.js';
import { runToolInstaller } from '../integrations/runner.js';

// Resolve the working project directory — allows tests to inject via env var
function getProjectDir(): string {
  return process.env.KDOC_PROJECT_DIR ?? process.cwd();
}

// Default areas enabled per pack
const PACK_DEFAULT_AREAS: Record<string, string[]> = {
  nextjs: [
    'adr',
    'tldr',
    'roadmap',
    'design',
    'guides',
    'agent-memory',
    'runbooks',
    'templates',
    'context-pack',
    'index',
  ],
  'swift-ios': ['adr', 'tldr', 'roadmap', 'guides', 'agent-memory', 'templates', 'context-pack'],
};

// When --yes is used without packs, enable all areas by default.
// With packs, use the pack-specific defaults.
const DEFAULT_AREAS: string[] = [...KNOWN_AREAS];
const DEFAULT_VAULT_CATEGORIES = ['Notes', 'Decisions', 'Research', 'Templates'];
const TOPOLOGY_OPTIONS = ['single', 'monorepo', 'vault'] as const;

function parseTopologyOption(value: unknown): 'single' | 'monorepo' | 'vault' | null {
  if (typeof value !== 'string') return null;
  const normalized = value.trim().toLowerCase();
  if ((TOPOLOGY_OPTIONS as readonly string[]).includes(normalized)) {
    return normalized as 'single' | 'monorepo' | 'vault';
  }
  return null;
}

function makeTemplateResolver(): TemplateResolver {
  return createTemplateResolver(SYNTHETIC_TEMPLATES);
}

function buildConfig(options: {
  packs: string[];
  tools: string[];
  areas: string[];
  topology: 'single' | 'monorepo' | 'vault';
  packages?: Record<string, { path: string; areas?: Record<string, { enabled: boolean; scopes?: string[] }> }>;
  categories?: Record<string, { label: string; template?: string; description?: string }>;
}): KdocConfig {
  const { packs, tools, areas, topology, packages = {}, categories } = options;
  const areaMap: Record<string, { enabled: boolean }> = {};
  for (const area of KNOWN_AREAS) {
    areaMap[area] = { enabled: areas.includes(area) };
  }
  return {
    version: 2,
    root: 'Knowledge',
    packs,
    tools,
    areas: areaMap,
    topology,
    packages,
    ...(categories ? { categories } : {}),
    governance: {
      'sync-check': true,
      wikilinks: true,
      'adr-governance': true,
      'index-build': true,
      'intent-check': true,
      'enforced-paths': [],
    },
    scripts: { prefix: 'kdoc' },
    extensionAreas: [],
  };
}

function printSummary(summary: {
  created: string[];
  merged: string[];
  skipped: string[];
  conflicts: string[];
  errors: Array<{ path: string; error: string }>;
}): void {
  console.log('\nScaffold complete:');
  if (summary.created.length) console.log(`  Created : ${summary.created.length} file(s)`);
  if (summary.merged.length) console.log(`  Merged  : ${summary.merged.length} file(s)`);
  if (summary.skipped.length) console.log(`  Skipped : ${summary.skipped.length} file(s)`);
  if (summary.conflicts.length) {
    console.log(`  Conflicts: ${summary.conflicts.length} file(s) (review manually)`);
    for (const c of summary.conflicts) console.log(`    - ${c}`);
  }
  if (summary.errors.length) {
    console.log(`  Errors  : ${summary.errors.length} file(s)`);
    for (const e of summary.errors) console.log(`    - ${e.path}: ${e.error}`);
  }
}

export function createInitCommand(): Command {
  const cmd = new Command('init');

  cmd
    .description('Scaffold a Knowledge documentation structure into this project')
    .option('--pack <packs>', 'Comma-separated list of packs (nextjs,swift-ios)')
    .option('--tools <tools>', 'Comma-separated list of AI tools (claude-code,codex)')
    .option('--topology <topology>', 'Knowledge topology (single, monorepo, vault)')
    .option('--yes', 'Non-interactive: skip all prompts and use detected defaults')
    .option('--dry-run', 'Show what would be done without making changes')
    .option('--verbose', 'Log each file operation as it runs')
    .action(async (options) => {
      const projectDir = getProjectDir();
      const yes: boolean = !!options.yes;
      const dryRun: boolean = !!options.dryRun;
      const verbose: boolean = !!options.verbose;
      const selectedTopologyOption = parseTopologyOption(options.topology);

      try {
        if (options.topology && !selectedTopologyOption) {
          console.error('Error: --topology must be one of: single, monorepo, vault.');
          process.exitCode = 1;
          return;
        }

        // F-010: When already initialized and --dry-run, skip prompts entirely
        // and just compute the diff plan from current config vs desired state.
        if (dryRun && configExists(projectDir)) {
          const existingConfig = loadConfig(projectDir);
          if (existingConfig) {
            // Merge requested flags into existing config so dry-run shows
            // what would change if the flags were applied.
            const mergedConfig = { ...existingConfig };
            if (selectedTopologyOption) mergedConfig.topology = selectedTopologyOption;
            if (options.tools) {
              mergedConfig.tools = (options.tools as string).split(',').map((s: string) => s.trim()).filter(Boolean);
            }
            if (options.pack) {
              mergedConfig.packs = (options.pack as string).split(',').map((s: string) => s.trim()).filter(Boolean);
            }

            const resolver = makeTemplateResolver();
            const detection = await detectProject(projectDir);
            const existingLock = loadLock(projectDir);
            const operations = planScaffold({
              config: mergedConfig,
              detection,
              lock: existingLock,
              projectDir,
              templateResolver: resolver,
            });

            // F-028: Detect own merge markers — report SKIP instead of CONFLICT
            for (const op of operations) {
              if (op.type === 'CONFLICT') {
                const absPath = join(projectDir, op.path);
                if (existsSync(absPath)) {
                  const content = readFileSync(absPath, 'utf8');
                  if (content.includes('<!-- kdoc:') || content.includes('"kdoc:')) {
                    op.type = 'SKIP';
                    op.reason = 'kdoc markers already present';
                  }
                }
              }
            }

            const creates = operations.filter((o) => o.type === 'CREATE').length;
            const merges = operations.filter((o) => o.type === 'MERGE').length;
            const skips = operations.filter((o) => o.type === 'SKIP').length;
            const conflicts = operations.filter((o) => o.type === 'CONFLICT').length;
            console.log(`\nPlan: ${creates} create, ${merges} merge, ${skips} skip, ${conflicts} conflict`);
            for (const op of operations) {
              console.log(`  [${op.type.padEnd(8)}] ${op.path}`);
            }
            console.log('\nDry run complete. No files were changed.');
            return;
          }
        }

        // --- Detect ---
        const detection = await detectProject(projectDir);
        const topologyDetection = detectTopology(projectDir);
        const detectedPackages = detectPackages(projectDir);

        // --- Interrupted install check ---
        if (hasPendingLockTmp(projectDir)) {
          if (!yes) {
            // Interactive: offer Resume / Start fresh (Undo is Plan 2B)
            const action = await select({
              message: 'Previous install was interrupted. What would you like to do?',
              choices: [
                { name: 'Resume from partial state', value: 'resume' },
                { name: 'Start fresh (delete partial state)', value: 'fresh' },
              ],
            });
            if (action === 'fresh') {
              cleanupLockTmp(projectDir);
            }
            // 'resume' falls through — executor picks up the .lock.tmp state
          }
          // With --yes, default to resume (safest option — no data loss)
        }

        // --- Determine packs ---
        let selectedPacks: string[];
        if (options.pack) {
          selectedPacks = (options.pack as string)
            .split(',')
            .map((s: string) => s.trim())
            .filter(Boolean);
        } else if (yes) {
          selectedPacks = detection.stack.packs.map((p) => p.name);
        } else {
          selectedPacks = await checkbox({
            message: 'Which technology packs would you like to install?',
            choices: KNOWN_PACKS.map((p) => ({
              name: p,
              value: p,
              checked: detection.stack.packs.some((dp) => dp.name === p),
            })),
          });
        }

        // Validate packs against known list
        for (const pack of selectedPacks) {
          if (!(KNOWN_PACKS as readonly string[]).includes(pack)) {
            console.error(`Error: Unknown pack "${pack}". Valid packs: ${KNOWN_PACKS.join(', ')}`);
            process.exitCode = 1;
            return;
          }
        }

        // --- Determine tools ---
        let selectedTools: string[];
        if (options.tools) {
          selectedTools = (options.tools as string)
            .split(',')
            .map((s: string) => s.trim())
            .filter(Boolean);
        } else if (yes) {
          selectedTools = detection.aiTools.tools;
        } else {
          selectedTools = await checkbox({
            message: 'Which AI tool integrations would you like to configure?',
            choices: KNOWN_TOOLS.map((t) => ({
              name: t,
              value: t,
              checked: detection.aiTools.tools.includes(t),
            })),
          });
        }

        // Validate tools against known list
        for (const tool of selectedTools) {
          if (!(KNOWN_TOOLS as readonly string[]).includes(tool)) {
            console.error(`Error: Unknown tool "${tool}". Valid tools: ${KNOWN_TOOLS.join(', ')}`);
            process.exitCode = 1;
            return;
          }
        }

        // --- Determine topology ---
        let selectedTopology: 'single' | 'monorepo' | 'vault';
        if (selectedTopologyOption) {
          selectedTopology = selectedTopologyOption;
        } else if (yes) {
          selectedTopology =
            topologyDetection.suggested === 'monorepo' ? 'monorepo' : 'single';
        } else {
          selectedTopology = await select({
            message: `Project topology (detected: ${topologyDetection.suggested})`,
            default: topologyDetection.suggested,
            choices: [
              { name: 'Single project', value: 'single' },
              { name: 'Monorepo (multiple packages)', value: 'monorepo' },
              { name: 'Knowledge vault (no code)', value: 'vault' },
            ],
          });
        }

        // --- Determine monorepo packages / vault categories ---
        let selectedPackages: Record<string, { path: string }> = {};
        let selectedCategories: Record<string, { label: string }> | undefined;

        if (selectedTopology === 'monorepo') {
          const detectedPackageEntries = Object.entries(detectedPackages.packages);
          if (yes) {
            selectedPackages = Object.fromEntries(
              detectedPackageEntries.map(([name, path]) => [name, { path }]),
            );
          } else if (detectedPackageEntries.length > 0) {
            const chosen = await checkbox({
              message: 'Which packages should get Knowledge scopes?',
              choices: detectedPackageEntries.map(([name, path]) => ({
                name: `${name} (${path})`,
                value: name,
                checked: true,
              })),
            });
            selectedPackages = Object.fromEntries(
              chosen.map((name) => [name, { path: detectedPackages.packages[name] }]),
            );
          }
        }

        if (selectedTopology === 'vault') {
          const categoryInput = yes
            ? DEFAULT_VAULT_CATEGORIES.join(', ')
            : await input({
                message: 'Vault categories (comma-separated)',
                default: DEFAULT_VAULT_CATEGORIES.join(', '),
              });

          const categoryNames = categoryInput
            .split(',')
            .map((value) => value.trim())
            .filter(Boolean);

          selectedCategories = Object.fromEntries(
            categoryNames.map((name) => [name, { label: name }]),
          );
        }

        // --- Determine areas ---
        let selectedAreas: string[];
        if (selectedTopology === 'vault') {
          selectedAreas = [];
        } else if (yes) {
          const packDefaults =
            selectedPacks.length > 0
              ? [...new Set(selectedPacks.flatMap((p) => PACK_DEFAULT_AREAS[p] ?? DEFAULT_AREAS))]
              : DEFAULT_AREAS;
          selectedAreas = packDefaults;
        } else {
          const packDefaults =
            selectedPacks.length > 0
              ? [...new Set(selectedPacks.flatMap((p) => PACK_DEFAULT_AREAS[p] ?? DEFAULT_AREAS))]
              : DEFAULT_AREAS;
          selectedAreas = await checkbox({
            message: 'Which Knowledge areas would you like to enable?',
            choices: KNOWN_AREAS.map((a) => ({
              name: a,
              value: a,
              checked: packDefaults.includes(a),
            })),
          });
        }

        // --- Build config in memory (not written yet) ---
        const config = buildConfig({
          packs: selectedPacks,
          tools: selectedTools,
          areas: selectedAreas,
          topology: selectedTopology,
          packages: selectedPackages,
          categories: selectedCategories,
        });

        // --- Plan ---
        const resolver = makeTemplateResolver();
        const existingLock = loadLock(projectDir);
        const operations = planScaffold({
          config,
          detection,
          lock: existingLock,
          projectDir,
          templateResolver: resolver,
        });

        if (verbose || dryRun) {
          const creates = operations.filter((o) => o.type === 'CREATE').length;
          const merges = operations.filter((o) => o.type === 'MERGE').length;
          const skips = operations.filter((o) => o.type === 'SKIP').length;
          const conflicts = operations.filter((o) => o.type === 'CONFLICT').length;
          console.log(`\nPlan: ${creates} create, ${merges} merge, ${skips} skip, ${conflicts} conflict`);
        }

        if (dryRun) {
          for (const op of operations) {
            console.log(`  [${op.type.padEnd(8)}] ${op.path}`);
          }
          console.log('\nDry run complete. No files were changed.');
          return;
        }

        // --- Build template contents map for executor ---
        // op.source is either a synthetic template key (e.g., 'core/templates/gitkeep')
        // or an absolute filesystem path (from resolveTemplateSource).
        // Try the resolver first (handles synthetic templates), then fall back to
        // reading the absolute path directly for filesystem-resolved templates.
        const templateContents = new Map<string, string>();
        for (const op of operations) {
          const resolved = resolver(op.source);
          if (resolved) {
            templateContents.set(op.source, resolved.content);
          } else if (existsSync(op.source)) {
            // op.source is an absolute path from a previous resolution — read directly
            templateContents.set(op.source, readFileSync(op.source, 'utf8'));
          }
        }

        // --- Execute ---
        const summary = await executeScaffold({
          operations,
          config,
          projectDir,
          kdocVersion: getKdocVersion(),
          templateContents,
          dryRun,
          verbose,
          onProgress: verbose
            ? (op, result) => console.log(`  [${result.toUpperCase().padEnd(8)}] ${op.path}`)
            : undefined,
        });

        // --- Install pack assets (templates, guides, design, scripts) ---
        for (const pack of config.packs) {
          const packResult = await installPackAssets(pack, projectDir, config, {
            dryRun,
          });
          if (packResult.errors.length > 0) {
            for (const e of packResult.errors) console.warn(`Warning: ${e}`);
          }
        }

        // --- Persist config (only on success) ---
        writeConfig(projectDir, config);

        // --- Run tool installers ---
        for (const tool of selectedTools) {
          try {
            const toolResult = runToolInstaller(tool, projectDir, { yes });
            for (const warning of toolResult.warnings) {
              console.warn(`Warning: ${warning}`);
            }
          } catch (err) {
            console.warn(`Warning: tool installer for "${tool}" failed: ${err instanceof Error ? err.message : String(err)}`);
          }
        }

        // --- Report ---
        printSummary(summary);

        if (summary.errors.length > 0) {
          process.exitCode = 1;
        }
      } catch (err) {
        const message = err instanceof Error ? err.message : String(err);
        console.error(`Error: ${message}`);
        process.exitCode = 1;
      }
    });

  return cmd;
}
