import { existsSync, readFileSync, readdirSync } from 'node:fs';
import { join, dirname, basename } from 'node:path';
import { fileURLToPath } from 'node:url';
import type { KdocConfig, LockFileEntry } from '../config/schema.js';
import { loadLock, appendFileEntry, finalizeLock } from '../config/lock.js';
import { safeWriteFile, ensureDir } from '../utils/fs.js';
import { hashString } from '../utils/hash.js';
import { renderTemplate } from '../templates/renderer.js';
import { getGitOwner } from '../utils/git.js';

/**
 * Resolve the directory containing this file at runtime.
 * In source: cli/src/packs/
 * After tsup bundle: cli/dist/ (all code is in dist/index.js)
 * We use this to navigate to the packs/ directory.
 */
const __dirname = dirname(fileURLToPath(import.meta.url));

/** Mapping from pack source directory to target project directory */
const ASSET_MAPPINGS: Array<{ sourceDir: string; targetPrefix: (knowledgeRoot: string, packName: string) => string }> = [
  { sourceDir: 'templates', targetPrefix: (kr, p) => join(kr, 'Templates', p) },
  { sourceDir: 'guides', targetPrefix: (kr, p) => join(kr, 'Guides', p) },
  { sourceDir: 'design', targetPrefix: (kr, p) => join(kr, 'Design', p) },
  { sourceDir: 'scripts', targetPrefix: (_kr, p) => join('scripts', 'kdoc', p) },
];

export interface PackInstallResult {
  installed: string[];
  skipped: string[];
  errors: string[];
}

export interface PackManifest {
  name: string;
  displayName: string;
  description: string;
  detect: { files: string[]; dependencies?: string[]; packageManager?: string[] };
  defaults: { scopes: string[]; 'enforced-paths': string[]; 'scripts-prefix'?: string; 'scripts-runner'?: string };
  areas?: Record<string, unknown>;
  roadmap?: Record<string, unknown>;
}

export interface PackManagedFile {
  path: string;
  templateName: string;
}

/** Resolve the absolute path to the packs directory within the kdoc package. */
export function getPacksRoot(): string {
  // After tsup bundling, __dirname is cli/dist/. Navigate: dist/ → cli/ → kdoc/ → packs/
  // In source (vitest), __dirname is cli/src/packs/. Navigate: packs/ → src/ → cli/ → kdoc/ → packs/
  // Try the bundled path first, fall back to source path.
  const bundledPath = join(__dirname, '..', '..', 'packs');
  if (existsSync(bundledPath)) return bundledPath;
  return join(__dirname, '..', '..', '..', 'packs');
}

export function getPackRoot(packName: string): string {
  return join(getPacksRoot(), packName);
}

export function loadPackManifest(packName: string): PackManifest {
  const manifestPath = join(getPackRoot(packName), 'pack.json');
  if (!existsSync(manifestPath)) {
    throw new Error(`Pack manifest not found: ${manifestPath}`);
  }
  return JSON.parse(readFileSync(manifestPath, 'utf8')) as PackManifest;
}

/** Walk a directory tree and return all file paths relative to root. */
function walkRelative(root: string, base = ''): string[] {
  if (!existsSync(root)) return [];
  const entries = readdirSync(root, { withFileTypes: true });
  const files: string[] = [];
  for (const entry of entries) {
    const rel = base ? join(base, entry.name) : entry.name;
    if (entry.isDirectory()) {
      files.push(...walkRelative(join(root, entry.name), rel));
    } else if (entry.isFile()) {
      files.push(rel);
    }
  }
  return files;
}

function buildPackRenderValues(projectDir: string, packName: string): Record<string, string> {
  const values: Record<string, string> = {
    PROJECT_NAME: basename(projectDir) || 'project',
    DATE: new Date().toISOString().slice(0, 10),
    SCOPE: 'root',
    KNOWLEDGE_ROOT: 'Knowledge',
    OWNER: getGitOwner(projectDir) || 'repository owner',
    ADR_NEXT_SEQUENCE: '0001',
    TLDR_SCOPES: 'Frontend, Backend, Shared',
    TLDR_STRUCTURE_COMMENT: '|- Frontend/\n|- Backend/\n\\- Shared/',
    WIKILINK_PREFIX: '',
  };
  return values;
}

export function listPackManagedFiles(
  packName: string,
  config: KdocConfig,
): PackManagedFile[] {
  const packRoot = getPackRoot(packName);
  const knowledgeRoot = config.root ?? 'Knowledge';
  const files: PackManagedFile[] = [];

  for (const mapping of ASSET_MAPPINGS) {
    const sourceDir = join(packRoot, mapping.sourceDir);
    const targetPrefix = mapping.targetPrefix(knowledgeRoot, packName);

    for (const relFile of walkRelative(sourceDir)) {
      files.push({
        path: join(targetPrefix, relFile),
        templateName: `packs/${packName}/${mapping.sourceDir}/${relFile}`,
      });
    }
  }

  return files;
}

/**
 * Install pack assets into the target project.
 * Copies templates, guides, design, and scripts from the pack directory into
 * namespaced project directories. Files are rendered through the template engine
 * for placeholder replacement.
 *
 * Idempotent: existing files with matching content are skipped.
 */
export async function installPackAssets(
  packName: string,
  projectDir: string,
  config: KdocConfig,
  options: { dryRun?: boolean; force?: boolean } = {},
): Promise<PackInstallResult> {
  const { dryRun = false, force = false } = options;
  const packRoot = getPackRoot(packName);
  const knowledgeRoot = config.root ?? 'Knowledge';
  const result: PackInstallResult = { installed: [], skipped: [], errors: [] };

  if (!existsSync(packRoot)) {
    result.errors.push(`Pack directory not found: ${packRoot}`);
    return result;
  }

  const renderValues = buildPackRenderValues(projectDir, packName);

  // Load existing lock for merge semantics (Task 2.0)
  const existingLock = dryRun ? null : loadLock(projectDir);

  for (const mapping of ASSET_MAPPINGS) {
    const sourceDir = join(packRoot, mapping.sourceDir);
    const targetPrefix = mapping.targetPrefix(knowledgeRoot, packName);
    const files = walkRelative(sourceDir);

    for (const relFile of files) {
      const sourcePath = join(sourceDir, relFile);
      const targetRelPath = join(targetPrefix, relFile);
      const targetAbsPath = join(projectDir, targetRelPath);

      try {
        // Read source content
        let content = readFileSync(sourcePath, 'utf8');

        // Render templates for placeholder filling (only markdown files)
        if (relFile.endsWith('.md') && content.includes('{{')) {
          content = renderTemplate(content, renderValues).content;
        }

        const contentHash = hashString(content);

        // Idempotency: skip if target exists with same content
        if (existsSync(targetAbsPath)) {
          const existingContent = readFileSync(targetAbsPath, 'utf8');
          const existingHash = hashString(existingContent);
          if (existingHash === contentHash) {
            result.skipped.push(targetRelPath);
            continue;
          }
          // File exists but content differs — skip unless force
          if (!force) {
            result.skipped.push(targetRelPath);
            continue;
          }
        }

        if (dryRun) {
          result.installed.push(targetRelPath);
          continue;
        }

        // Write the file
        ensureDir(dirname(targetAbsPath));
        safeWriteFile(targetAbsPath, content);
        result.installed.push(targetRelPath);

        // Record in lock — only templates are managed by update; guides/design/scripts
        // are static pack assets that should not be treated as scaffold-managed templates
        if (existingLock && mapping.sourceDir === 'templates') {
          const entry: LockFileEntry = {
            action: 'created',
            hash: contentHash,
            templateHash: contentHash,
            template: `packs/${packName}/${mapping.sourceDir}/${relFile}`,
          };
          appendFileEntry(projectDir, existingLock, targetRelPath, entry);
        }
      } catch (err) {
        result.errors.push(`${targetRelPath}: ${err instanceof Error ? err.message : String(err)}`);
      }
    }
  }

  // Finalize lock after all pack files are written
  if (!dryRun && existingLock) {
    finalizeLock(projectDir);
  }

  return result;
}
