import { existsSync, readdirSync, readFileSync } from 'node:fs';
import { join, relative, basename } from 'node:path';
import fg from 'fast-glob';
import type { Topology } from '../config/schema.js';
import { getPacksRoot, type PackManifest } from '../packs/installer.js';

export interface DetectedPack {
  name: string;
  /** 0 = root, 1 = one level deep, 2 = two levels deep */
  depth: number;
  /** Absolute path to the indicator file that triggered detection */
  path: string;
}

export interface DetectedStack {
  packs: DetectedPack[];
  isMonorepo: boolean;
}

export interface DetectedKnowledgeState {
  hasKnowledgeDir: boolean;
  existingAreas: string[];
  fileCount: number;
  hasConfig: boolean;
  hasLock: boolean;
  hasPendingLockTmp: boolean;
}

export interface DetectedAITools {
  tools: string[];
}

export interface DetectionResult {
  stack: DetectedStack;
  knowledge: DetectedKnowledgeState;
  aiTools: DetectedAITools;
}

// --- Stack detection ---

interface StackIndicator {
  pattern: string;
  pack: string;
}

/**
 * Load detection patterns from pack.json manifests.
 * Falls back to hardcoded patterns if pack.json files are unavailable.
 */
function loadStackIndicators(): StackIndicator[] {
  const indicators: StackIndicator[] = [];
  const packsRoot = getPacksRoot();

  if (!existsSync(packsRoot)) {
    // Fallback: hardcoded patterns for marketplace builds
    return [
      { pattern: 'next.config.ts', pack: 'nextjs' },
      { pattern: 'next.config.js', pack: 'nextjs' },
      { pattern: 'next.config.mjs', pack: 'nextjs' },
      { pattern: 'Package.swift', pack: 'swift-ios' },
      { pattern: '*.xcodeproj', pack: 'swift-ios' },
    ];
  }

  for (const entry of readdirSync(packsRoot, { withFileTypes: true })) {
    if (!entry.isDirectory()) continue;
    const manifestPath = join(packsRoot, entry.name, 'pack.json');
    if (!existsSync(manifestPath)) continue;
    try {
      const manifest = JSON.parse(readFileSync(manifestPath, 'utf8')) as PackManifest;
      for (const pattern of manifest.detect.files) {
        indicators.push({ pattern, pack: manifest.name });
      }
    } catch {
      // Skip malformed pack manifests
    }
  }

  return indicators.length > 0 ? indicators : [
    { pattern: 'next.config.ts', pack: 'nextjs' },
    { pattern: 'next.config.js', pack: 'nextjs' },
    { pattern: 'next.config.mjs', pack: 'nextjs' },
    { pattern: 'Package.swift', pack: 'swift-ios' },
    { pattern: '*.xcodeproj', pack: 'swift-ios' },
  ];
}

const STACK_INDICATORS: StackIndicator[] = loadStackIndicators();

async function detectStack(projectDir: string): Promise<DetectedStack> {
  const detected = new Map<string, DetectedPack>();

  // Build patterns for depth 0, 1, and 2
  const patterns: string[] = [];
  for (const indicator of STACK_INDICATORS) {
    patterns.push(indicator.pattern);            // depth 0
    patterns.push(`*/${indicator.pattern}`);     // depth 1
    patterns.push(`*/*/${indicator.pattern}`);   // depth 2
  }

  const matches = await fg(patterns, {
    cwd: projectDir,
    absolute: true,
    onlyFiles: false,
    ignore: ['node_modules/**', '.git/**'],
  });

  for (const matchPath of matches) {
    const rel = relative(projectDir, matchPath);
    const parts = rel.split('/');
    const depth = parts.length - 1;

    const fileName = parts[parts.length - 1];
    const indicator = STACK_INDICATORS.find(ind => {
      if (ind.pattern.includes('*')) {
        // Glob pattern: check extension
        const ext = ind.pattern.replace('*', '');
        return fileName.endsWith(ext);
      }
      return fileName === ind.pattern;
    });

    if (!indicator) continue;

    const pack = indicator.pack;
    // Only keep the shallowest occurrence of each pack
    const existing = detected.get(pack);
    if (!existing || depth < existing.depth) {
      detected.set(pack, { name: pack, depth, path: matchPath });
    }
  }

  const packs = Array.from(detected.values());
  const isMonorepo = packs.some(p => p.depth > 0);

  return { packs, isMonorepo };
}

// --- Knowledge state detection ---

function countFilesRecursive(dir: string): number {
  let count = 0;
  const entries = readdirSync(dir, { withFileTypes: true });
  for (const entry of entries) {
    if (entry.isFile()) count++;
    else if (entry.isDirectory()) count += countFilesRecursive(join(dir, entry.name));
  }
  return count;
}

function detectKnowledgeState(projectDir: string): DetectedKnowledgeState {
  const knowledgeDir = join(projectDir, 'Knowledge');
  const hasKnowledgeDir = existsSync(knowledgeDir);

  let existingAreas: string[] = [];
  let fileCount = 0;

  if (hasKnowledgeDir) {
    const entries = readdirSync(knowledgeDir, { withFileTypes: true });
    existingAreas = entries
      .filter(e => e.isDirectory())
      .map(e => e.name);
    fileCount = countFilesRecursive(knowledgeDir);
  }

  return {
    hasKnowledgeDir,
    existingAreas,
    fileCount,
    hasConfig: existsSync(join(projectDir, '.kdoc.yaml')),
    hasLock: existsSync(join(projectDir, '.kdoc.lock')),
    hasPendingLockTmp: existsSync(join(projectDir, '.kdoc.lock.tmp')),
  };
}

// --- AI tool detection ---

function detectAITools(projectDir: string): DetectedAITools {
  const tools: string[] = [];

  // Claude Code indicators
  if (
    existsSync(join(projectDir, '.claude')) ||
    existsSync(join(projectDir, '.claude-plugin'))
  ) {
    tools.push('claude-code');
  }

  // Codex indicators
  if (
    existsSync(join(projectDir, 'AGENTS.md')) ||
    existsSync(join(projectDir, '.codex'))
  ) {
    tools.push('codex');
  }

  return { tools };
}

// --- Topology detection ---

export interface TopologyDetection {
  suggested: Topology;
  reason: string;
}

export interface DetectedPackages {
  packages: Record<string, string>;
}

/**
 * Detect whether this project is a single project, monorepo, or knowledge vault.
 * Checks workspace metadata first, then falls back to code-file heuristics.
 */
export function detectTopology(projectDir: string): TopologyDetection {
  // Check npm workspaces
  const pkgJsonPath = join(projectDir, 'package.json');
  if (existsSync(pkgJsonPath)) {
    try {
      const pkg = JSON.parse(readFileSync(pkgJsonPath, 'utf8'));
      if (pkg.workspaces && (Array.isArray(pkg.workspaces) || pkg.workspaces.packages)) {
        return { suggested: 'monorepo', reason: 'package.json workspaces detected' };
      }
    } catch {
      // Not valid JSON — continue
    }
  }

  // Check pnpm workspaces
  if (existsSync(join(projectDir, 'pnpm-workspace.yaml'))) {
    return { suggested: 'monorepo', reason: 'pnpm-workspace.yaml detected' };
  }

  // Check for code indicators — if none found, suggest vault
  const hasPackageJson = existsSync(pkgJsonPath);
  const hasCodeFiles = fg.sync(['**/*.{ts,js,tsx,jsx,py,rb,go,rs,swift,java,kt}'], {
    cwd: projectDir,
    ignore: ['node_modules/**', '.git/**', 'Knowledge/**'],
    onlyFiles: true,
    deep: 2,
  }).length > 0;

  if (!hasPackageJson && !hasCodeFiles) {
    return { suggested: 'vault', reason: 'No package.json or code files found' };
  }

  return { suggested: 'single', reason: 'Single project (no workspace metadata)' };
}

/**
 * Detect packages in a monorepo by parsing workspace patterns.
 * Returns a map of package name → relative path.
 */
export function detectPackages(projectDir: string): DetectedPackages {
  const packages: Record<string, string> = {};
  let patterns: string[] = [];

  // Try npm workspaces
  const pkgJsonPath = join(projectDir, 'package.json');
  if (existsSync(pkgJsonPath)) {
    try {
      const pkg = JSON.parse(readFileSync(pkgJsonPath, 'utf8'));
      if (Array.isArray(pkg.workspaces)) {
        patterns = pkg.workspaces;
      } else if (pkg.workspaces?.packages) {
        patterns = pkg.workspaces.packages;
      }
    } catch {
      // ignore
    }
  }

  // Try pnpm workspace
  if (patterns.length === 0) {
    const pnpmPath = join(projectDir, 'pnpm-workspace.yaml');
    if (existsSync(pnpmPath)) {
      try {
        const content = readFileSync(pnpmPath, 'utf8');
        // Simple YAML parsing for packages list
        const match = content.match(/packages:\s*\n((?:\s+-\s+.+\n?)+)/);
        if (match) {
          patterns = match[1]
            .split('\n')
            .map(l => l.replace(/^\s+-\s+['"]?/, '').replace(/['"]?\s*$/, ''))
            .filter(Boolean);
        }
      } catch {
        // ignore
      }
    }
  }

  if (patterns.length === 0) return { packages };

  // Resolve glob patterns to directories
  for (const pattern of patterns) {
    const matches = fg.sync(pattern, {
      cwd: projectDir,
      onlyDirectories: true,
      ignore: ['node_modules/**'],
    });

    for (const match of matches) {
      const pkgPath = join(projectDir, match, 'package.json');
      if (existsSync(pkgPath)) {
        try {
          const pkg = JSON.parse(readFileSync(pkgPath, 'utf8'));
          const name = pkg.name ?? basename(match);
          packages[name] = match;
        } catch {
          packages[basename(match)] = match;
        }
      } else {
        packages[basename(match)] = match;
      }
    }
  }

  return { packages };
}

// --- Public API ---

export async function detectProject(projectDir: string): Promise<DetectionResult> {
  const [stack, knowledge, aiTools] = await Promise.all([
    detectStack(projectDir),
    Promise.resolve(detectKnowledgeState(projectDir)),
    Promise.resolve(detectAITools(projectDir)),
  ]);

  return { stack, knowledge, aiTools };
}
