// cli/src/commands/create.ts
import { Command } from 'commander';
import { existsSync, readdirSync } from 'node:fs';
import { basename, join } from 'node:path';
import { loadConfig } from '../config/loader.js';
import { renderTemplate } from '../templates/renderer.js';
import { loadTemplate } from '../templates/catalog.js';
import type { KnowledgeScope } from '../topology/scopes.js';
import { resolveRootScope, resolveScopeForPackage } from '../topology/scopes.js';
import { knowledgePath } from '../topology/paths.js';
import { safeWriteFile, readFileSafe } from '../utils/fs.js';
import { slugify } from '../utils/strings.js';
import { readFileSync } from 'node:fs';
import { dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { parse as parseYaml } from 'yaml';

// ---- Supported types ----

const VALID_TYPES = [
  'adr',
  'tldr',
  'phase',
  'sub-phase',
  'flow-spec',
  'guide',
  'threat-model',
  'runbook',
  'test-map',
] as const;

type CreateType = (typeof VALID_TYPES)[number];

export interface CreateArgs {
  type: string;
  name: string;
  scope?: string;
  status?: string;
  package?: string;
  category?: string;
  parent?: string;
}

// ---- Validation ----

export function validateCreateArgs(args: CreateArgs): { valid: boolean; error?: string; warning?: string } {
  if (!VALID_TYPES.includes(args.type as CreateType)) {
    return { valid: false, error: `Unknown type "${args.type}". Valid types: ${VALID_TYPES.join(', ')}` };
  }
  if (!args.name || args.name.trim() === '') {
    return { valid: false, error: 'Name is required. Use: kdoc create <type> <name>' };
  }
  const kebabRegex = /^[a-z0-9]+(-[a-z0-9]+)*$/;
  let warning: string | undefined;
  if (!kebabRegex.test(args.name)) {
    const slugified = slugify(args.name);
    warning = `Name "${args.name}" will be transformed to "${slugified}"`;
  }
  if (args.package && args.category) {
    return { valid: false, error: 'Use either --package or --category, not both.' };
  }
  if (args.type === 'tldr' && !args.scope) {
    return { valid: false, error: 'TLDR requires --scope flag. Example: kdoc create tldr my-feature --scope Admin' };
  }
  if (args.type === 'sub-phase' && !args.parent) {
    return { valid: false, error: 'Sub-phase requires --parent flag. Example: kdoc create sub-phase "My Task" --parent 1' };
  }
  return { valid: true, warning };
}

// ---- ADR numbering ----

export function resolveAdrNumber(adrDir: string): string {
  if (!existsSync(adrDir)) return '0001';

  const entries = readdirSync(adrDir);
  const numbers = entries
    .map(f => {
      const match = f.match(/^ADR-(\d{4})-/);
      return match ? parseInt(match[1], 10) : 0;
    })
    .filter(n => n > 0);

  const max = numbers.length > 0 ? Math.max(...numbers) : 0;
  return String(max + 1).padStart(4, '0');
}

// ---- Phase numbering ----

function resolvePhaseNumber(phasesDir: string): number {
  if (!existsSync(phasesDir)) return 1;
  const entries = readdirSync(phasesDir);
  const numbers = entries
    .map(f => {
      const match = f.match(/^phase-(\d+)\.md$/);
      return match ? parseInt(match[1], 10) : 0;
    })
    .filter(n => n > 0);
  return numbers.length > 0 ? Math.max(...numbers) + 1 : 1;
}

function resolveSubPhaseNumber(parentDir: string, parentNum: string): number {
  if (!existsSync(parentDir)) return 1;
  const entries = readdirSync(parentDir);
  // Match both N.X.md (e.g., 1.1.md, 1.2.md) and plain X.md (e.g., 1.md, 2.md)
  const prefix = `${parentNum}.`;
  const numbers = entries
    .map(f => {
      // Try N.X.md format first (e.g., 1.1.md → X=1)
      if (f.startsWith(prefix) && f.endsWith('.md')) {
        const x = parseInt(f.slice(prefix.length, -3), 10);
        return isNaN(x) ? 0 : x;
      }
      // Fall back to plain X.md (e.g., 1.md → X=1)
      const match = f.match(/^(\d+)\.md$/);
      return match ? parseInt(match[1], 10) : 0;
    })
    .filter(n => n > 0);
  return numbers.length > 0 ? Math.max(...numbers) + 1 : 1;
}

// ---- Path resolution ----

interface ResolvePathOptions {
  scope?: KnowledgeScope;
  root?: string;
  adrNumber?: string;
  tldrScope?: string;
  parent?: string;
}

function resolveDocumentSlug(type: string, name: string): string {
  const slug = slugify(name);
  if (!slug) {
    throw new Error(`Unable to derive a filename slug for ${type} from "${name}".`);
  }
  return slug;
}

function buildAdrIntent(title: string): string {
  const normalized = title.trim().replace(/\s+/g, ' ');
  if (!normalized) return '';
  const sentence = normalized.charAt(0).toUpperCase() + normalized.slice(1);
  return sentence.endsWith('.') ? sentence : `${sentence}.`;
}

function replaceFrontmatterField(content: string, field: string, value: string): string {
  const serialized = JSON.stringify(value);
  const pattern = new RegExp(`^${field}:\\s*.*$`, 'm');
  return pattern.test(content)
    ? content.replace(pattern, `${field}: ${serialized}`)
    : content;
}

function normalizeCreatedContent(
  type: string,
  content: string,
  options: { name: string; slug: string; parent?: string; phaseNum?: number; subPhaseNum?: number },
): string {
  switch (type as CreateType) {
    case 'adr':
      return replaceFrontmatterField(content, 'intent', buildAdrIntent(options.name));
    case 'tldr':
      return replaceFrontmatterField(content, 'id', `tldr-${options.slug}`);
    case 'guide':
      return replaceFrontmatterField(content, 'id', `guide-${options.slug}`);
    case 'threat-model':
      return replaceFrontmatterField(content, 'id', `tm-${options.slug}`);
    case 'phase': {
      // F-016: Populate phase id with actual number
      let result = content;
      if (options.phaseNum) {
        result = replaceFrontmatterField(result, 'id', `phase-${options.phaseNum}`);
      }
      return result;
    }
    case 'sub-phase': {
      // F-034: Populate sub-phase id and parent_phase with actual values
      let result = content;
      if (options.parent && options.subPhaseNum) {
        result = replaceFrontmatterField(result, 'id', `${options.parent}.${options.subPhaseNum}`);
        result = replaceFrontmatterField(result, 'parent_phase', `phase-${options.parent}`);
      }
      return result;
    }
    default:
      return content;
  }
}

function findDuplicateAdrPath(adrDir: string, slug: string): string | null {
  if (!existsSync(adrDir)) return null;

  for (const entry of readdirSync(adrDir)) {
    const match = entry.match(/^ADR-\d{4}-(.+)\.md$/);
    if (!match) continue;
    if (slugify(match[1]) === slug) {
      return join(adrDir, entry);
    }
  }

  return null;
}

export function resolveCreatePath(type: string, name: string, opts: ResolvePathOptions): string {
  const { scope, root, adrNumber, tldrScope, parent } = opts;
  const knowledgeScope: KnowledgeScope = scope ?? {
    name: 'root',
    type: 'root',
    knowledgeRoot: root ?? '',
    areas: {},
  };
  const slug = resolveDocumentSlug(type, name);

  if (knowledgeScope.type === 'category') {
    return join(knowledgeScope.knowledgeRoot, `${slug}.md`);
  }

  switch (type as CreateType) {
    case 'adr':
      return knowledgePath(knowledgeScope, 'adr', `ADR-${adrNumber}-${slug}.md`);
    case 'tldr':
      return knowledgePath(knowledgeScope, 'tldr', join(tldrScope ?? '_noscope', `${slug}.md`));
    case 'phase': {
      // F-032/F-015: Use sequential phase-N.md naming to match roadmap parser
      const phasesDir = knowledgePath(knowledgeScope, 'roadmap', 'phases');
      const phaseNum = resolvePhaseNumber(phasesDir);
      return join(phasesDir, `phase-${phaseNum}.md`);
    }
    case 'sub-phase': {
      // F-033/F-017: Nest under parent phase directory as phases/phase-N/N.X.md
      const phasesDir = knowledgePath(knowledgeScope, 'roadmap', 'phases');
      const parentDir = join(phasesDir, `phase-${parent}`);
      const subNum = resolveSubPhaseNumber(parentDir, parent!);
      return join(parentDir, `${parent}.${subNum}.md`);
    }
    case 'flow-spec':
      return knowledgePath(knowledgeScope, 'design', `${slug}-flow.md`);
    case 'guide':
      return knowledgePath(knowledgeScope, 'guides', `${slug}.md`);
    case 'threat-model':
      return knowledgePath(knowledgeScope, 'threat-models', `${slug}.md`);
    case 'runbook':
      return knowledgePath(knowledgeScope, 'runbooks', `${slug}.md`);
    case 'test-map':
      return knowledgePath(knowledgeScope, 'templates', `${slug}-test-map.md`);
    default:
      throw new Error(`Unknown type: ${type}`);
  }
}

// ---- Commander registration ----

export function registerCreateCommand(program: Command): void {
  const cmd = new Command('create');

  cmd
    .description('Create a new Knowledge document (adr, tldr, phase, sub-phase, flow-spec, guide, runbook, threat-model, test-map)')
    .argument('<type>', 'Document type to create')
    .argument('[name]', 'Document name (kebab-case)')
    .option('--scope <scope>', 'Scope for TLDR documents (required for tldr type)')
    .option('--package <name>', 'Create the document inside a configured monorepo package scope')
    .option('--category <name>', 'Create the document inside a configured vault category')
    .option('--status <status>', 'Initial status (default: proposed for ADR, draft for TLDR)')
    .option('--parent <number>', 'Parent phase number (required for sub-phase)')
    .option('--dry-run', 'Show what would be done without making changes')
    .option('--yes', 'Non-interactive mode')
    .action(async (
      type: string,
      name: string | undefined,
      opts: { scope?: string; status?: string; package?: string; category?: string; parent?: string; dryRun?: boolean },
    ) => {
      const cwd = process.cwd();

      const args: CreateArgs = {
        type,
        name: name ?? '',
        scope: opts.scope,
        status: opts.status,
        package: opts.package,
        category: opts.category,
        parent: opts.parent,
      };
      const validation = validateCreateArgs(args);
      if (!validation.valid) {
        console.error(`Error: ${validation.error}`);
        process.exitCode = 1;
        return;
      }
      if (validation.warning) {
        console.warn(`Warning: ${validation.warning}`);
      }

      const config = loadConfig(cwd);
      if (!config) {
        console.error('Error: .kdoc.yaml not found. Run `kdoc init` first.');
        process.exitCode = 2;
        return;
      }

      if (opts.package && config.topology !== 'monorepo') {
        console.error('Error: --package can only be used when topology is "monorepo".');
        process.exitCode = 1;
        return;
      }

      if (opts.category && config.topology !== 'vault') {
        console.error('Error: --category can only be used when topology is "vault".');
        process.exitCode = 1;
        return;
      }

      let knowledgeScope: KnowledgeScope;
      if (opts.package) {
        const packageScope = resolveScopeForPackage(config, cwd, opts.package);
        if (!packageScope) {
          console.error(
            `Error: Unknown package "${opts.package}". Valid packages: ${Object.keys(config.packages ?? {}).join(', ')}`,
          );
          process.exitCode = 1;
          return;
        }
        knowledgeScope = packageScope;
      } else if (opts.category) {
        const categoryConfig = config.categories?.[opts.category];
        if (!categoryConfig) {
          console.error(
            `Error: Unknown category "${opts.category}". Valid categories: ${Object.keys(config.categories ?? {}).join(', ')}`,
          );
          process.exitCode = 1;
          return;
        }
        knowledgeScope = {
          name: opts.category,
          type: 'category',
          knowledgeRoot: join(cwd, config.root, opts.category),
          areas: {},
        };
      } else if (config.topology === 'vault') {
        console.error(
          `Error: Vault topology requires --category. Valid categories: ${Object.keys(config.categories ?? {}).join(', ')}`,
        );
        process.exitCode = 1;
        return;
      } else {
        knowledgeScope = resolveRootScope(config, cwd);
      }

      let adrNumber: string | undefined;
      const normalizedName = name!.trim();
      const documentSlug = resolveDocumentSlug(type, normalizedName);

      if (type === 'adr') {
        const adrDir = knowledgePath(knowledgeScope, 'adr');
        const duplicatePath = findDuplicateAdrPath(adrDir, documentSlug);
        if (duplicatePath) {
          console.error(`Error: ADR with the same title already exists: ${duplicatePath}`);
          process.exitCode = 1;
          return;
        }
        adrNumber = resolveAdrNumber(adrDir);
      }

      const outputPath = resolveCreatePath(type, normalizedName, {
        scope: knowledgeScope,
        adrNumber,
        tldrScope: opts.scope,
        parent: opts.parent,
      });

      if (existsSync(outputPath)) {
        console.error(`Error: File already exists: ${outputPath}`);
        process.exitCode = 1;
        return;
      }

      const templateContent = loadTemplate(type);
      const projectName = basename(cwd) || 'project';

      const defaultStatus = type === 'adr' ? 'proposed' : 'draft';
      const values: Record<string, string> = {
        ID: adrNumber ?? '',
        NUMBER: adrNumber ?? '',
        NAME: type === 'tldr' || type === 'threat-model' || type === 'flow-spec' ? documentSlug : normalizedName,
        TITLE: normalizedName,
        STATUS: opts.status ?? defaultStatus,
        SCOPE: knowledgeScope.type === 'root' ? 'root' : knowledgeScope.name,
        AREA: type,
        PROJECT_NAME: projectName,
        TYPE: type,
        KNOWLEDGE_ROOT: config.root,
        ...(opts.category ? { CATEGORY_NAME: opts.category, CATEGORY_LABEL: config.categories?.[opts.category]?.label ?? opts.category } : {}),
      };

      const { content, warnings } = renderTemplate(templateContent, values);

      for (const warning of warnings) {
        console.warn(`Warning: ${warning}`);
      }

      // Compute phase/sub-phase numbers for frontmatter normalization
      let phaseNum: number | undefined;
      let subPhaseNum: number | undefined;
      if (type === 'phase') {
        const phasesDir = knowledgePath(knowledgeScope, 'roadmap', 'phases');
        phaseNum = resolvePhaseNumber(phasesDir);
      }
      if (type === 'sub-phase' && opts.parent) {
        const phasesDir = knowledgePath(knowledgeScope, 'roadmap', 'phases');
        const parentDir = join(phasesDir, `phase-${opts.parent}`);
        subPhaseNum = resolveSubPhaseNumber(parentDir, opts.parent);
      }

      const normalizedContent = normalizeCreatedContent(type, content, {
        name: normalizedName,
        slug: documentSlug,
        parent: opts.parent,
        phaseNum,
        subPhaseNum,
      });

      if (opts.dryRun) {
        console.log(`[DRY RUN] Would create: ${outputPath}`);
        console.log('--- Preview ---');
        console.log(normalizedContent);
        console.log('--- End Preview ---');
        return;
      }

      safeWriteFile(outputPath, normalizedContent);
      console.log(`Created: ${outputPath}`);

      // Emit kdoc.artifact_created daemon event (fire-and-forget)
      try {
        const __create_dir = dirname(fileURLToPath(import.meta.url));
        const enginePath = join(__create_dir, '..', '..', '..', 'core', 'governance-engine.mjs');
        const engine = await import(enginePath);
        engine.emitDaemonEvent('kdoc.artifact_created', {
          type,
          name: normalizedName,
          path: outputPath,
        });
        if (type === 'phase' || type === 'sub-phase') {
          const phaseIdMatch = normalizedContent.match(/^id:\s*["']?(.+?)["']?\s*$/m);
          engine.emitDaemonEvent('roadmap.phase_created', {
            phase_id: phaseIdMatch?.[1] ?? null,
            phase_type: type,
            name: normalizedName,
            path: outputPath,
            parent_phase_id: type === 'sub-phase' && opts.parent ? `phase-${opts.parent}` : null,
          });
        }
      } catch {
        // Daemon event is best-effort
      }

      // B-7 fix: Post-create frontmatter validation using yaml.parse + schema
      try {
        const __create_dirname = dirname(fileURLToPath(import.meta.url));
        const schemaPath = join(__create_dirname, '..', '..', '..', 'core', 'schema', 'frontmatter-schemas.json');
        const schemas = JSON.parse(readFileSync(schemaPath, 'utf8'));
        const typeDef = schemas.types[type] ?? schemas.types[type.replace('-', '_')];
        if (typeDef) {
          const created = readFileSafe(outputPath) ?? '';
          const fmMatch = created.match(/^---\r?\n([\s\S]*?)\r?\n---/);
          if (fmMatch) {
            const parsed = parseYaml(fmMatch[1]);
            if (parsed && typeof parsed === 'object') {
              // Check required fields exist
              const missingFields = (typeDef.required ?? []).filter(
                (field: string) => !(field in (parsed as Record<string, unknown>))
              );
              if (missingFields.length > 0) {
                console.warn(`Warning: Created file is missing required frontmatter fields: ${missingFields.join(', ')}`);
              }
              // Check status values if applicable
              const status = (parsed as Record<string, unknown>).status;
              if (status && typeDef.status_values && !typeDef.status_values.includes(status)) {
                console.warn(`Warning: Invalid status "${status}". Valid values: ${typeDef.status_values.join(', ')}`);
              }
              // Check security-tier values if present
              const secTier = (parsed as Record<string, unknown>)['security-tier'];
              if (secTier && schemas.field_values?.['security-tier'] && !schemas.field_values['security-tier'].includes(secTier)) {
                console.warn(`Warning: Invalid security-tier "${secTier}". Valid values: ${schemas.field_values['security-tier'].join(', ')}`);
              }
            }
          }
        }
      } catch {
        // Validation is best-effort — don't block creation
      }
    });

  program.addCommand(cmd);
}
